const input = $input.first().json;
const identifier = $('Data Handler').item.json.data.remoteJid || '';
const msg = ($('Data Handler').item.json.data.text || '').toString().trim().replace(/\r/g, '');

const listBasesRaw = input.data || [];

let cadastroState = { step: 1, name: '', email: '', base: '' };
try {
  const raw = input.cadastro_state || input.value || input.propertyName || '';
  if (raw && typeof raw === 'string') {
    const parsed = JSON.parse(raw);
    if (parsed && typeof parsed.step === 'number') cadastroState = parsed;
  }
} catch (e) {}

const step = cadastroState.step;
let name = cadastroState.name || '';
let email = cadastroState.email || '';
let base = cadastroState.base || '';
let nextStep = step;
let message = '';
let cadastroValid = false;
let error = '';

function formatList(items, field) {
  field = field || 'Base';
  if (!items || !Array.isArray(items)) return '';
  return items.map(function(x, i) {
    return (i + 1) + ') ' + (x[field] || x.Base || x.nome || '');
  }).join('\n');
}

function validarBase(v, lista) {
  if (!lista || !lista.length) return true;
  return lista.some(function(x) {
    var b = (x.Base || x.nome || '').toString().toLowerCase();
    return b === (v || '').toLowerCase().trim();
  });
}

if (step === 1) {
  if (msg && msg.length >= 2) {
    name = msg.trim().slice(0, 100);
    nextStep = 2;
    message = 'Qual seu email?';
  } else {
    message = 'Qual seu nome? (m�nimo 2 caracteres)';
  }
} else if (step === 2) {
  if (msg && msg.includes('@') && msg.includes('.')) {
    email = msg.trim().slice(0, 100);
    nextStep = 3;
    if (listBasesRaw.length > 0) {
      message = 'Qual sua base? Escolha uma da lista:\n\n' + formatList(listBasesRaw, 'Base');
    } else {
      message = 'Qual sua base? (ex: RJ, SP, ADM)';
    }
  } else {
    message = msg ? 'Email inv�lido. Envie um email v�lido (ex: nome@empresa.com).' : 'Qual seu email?';
  }
} else if (step === 3) {
  if (msg && msg.trim()) {
    var baseInput = msg.trim();
    if (validarBase(baseInput, listBasesRaw)) {
      base = baseInput;
      cadastroValid = true;
      message = 'Cadastro conclu�do!';
    } else {
      error = 'Base inv�lida. Escolha uma da lista.';
      if (listBasesRaw.length > 0) {
        message = error + '\n\n' + formatList(listBasesRaw, 'Base');
      } else {
        message = error;
      }
    }
  } else {
    if (listBasesRaw.length > 0) {
      message = 'Qual sua base? Escolha uma da lista:\n\n' + formatList(listBasesRaw, 'Base');
    } else {
      message = 'Qual sua base? (ex: RJ, SP, ADM)';
    }
  }
} else {
  nextStep = 1;
  message = 'Qual seu nome? (m�nimo 2 caracteres)';
}

const out = {
  cadastroValid: cadastroValid,
  cadastroStep: nextStep,
  cadastroName: name,
  cadastroEmail: email,
  cadastroBase: base,
  cadastroState: JSON.stringify({ step: nextStep, name: name, email: email, base: base }),
  message: message,
  error: error
};
return [{ json: out }];

