// ========== HELPERS ==========
function parseValorBR(str) {
  if (!str || typeof str !== 'string') return null;
  const cleaned = str.replace(/R\$\s*/gi, '').replace(/\./g, '').replace(',', '.').trim();
  const num = parseFloat(cleaned);
  return isNaN(num) ? null : num;
}

function parseDataBR(str) {
  if (!str || typeof str !== 'string') return null;
  const m = str.match(/(\d{1,2})[\/\-](\d{1,2})[\/\-](\d{2,4})/);
  if (!m) return null;
  const d = parseInt(m[1], 10);
  const mo = parseInt(m[2], 10);
  const y = m[3].length === 2 ? 2000 + parseInt(m[3], 10) : parseInt(m[3], 10);
  if (d < 1 || d > 31 || mo < 1 || mo > 12) return null;
  const date = new Date(y, mo - 1, d);
  if (isNaN(date.getTime())) return null;
  return date.toISOString().slice(0, 10);
}

function formatList(items, field) {
  if (!items || !Array.isArray(items)) return '';
  return items.map((x, i) => `${i + 1}) ${x[field] || x.nome || x.Base || x.Forma || x.Nome || ''}`).join('\n');
}

function validarBase(v, lista) {
  if (!lista || !lista.length) return !!v?.trim();
  return lista.some(x => (x.Base || x.nome || '').toLowerCase() === (v || '').toLowerCase());
}

function validarLista(v, lista, field) {
  field = field || 'nome';
  if (!lista || !lista.length) return !!v?.trim();
  return lista.some(x => (x[field] || x.Forma || x.Nome || x.Base || '').toLowerCase() === (v || '').toLowerCase());
}

