const input = $input.first().json;
const rawStep = input.step;
const stepNum = typeof rawStep === 'number' && !isNaN(rawStep) ? rawStep : parseInt(String(rawStep ?? 1), 10);
const step = (isNaN(stepNum) || stepNum < 1) ? 1 : Math.min(stepNum, 14);
const sessionData = input.sessionData || {};
const userInput = (input.userInput || '').toString().trim();
const hasImage = !!input.hasImage;
const imageData = input.imageData || {};
const linkComprovante = input.link_comprovante || sessionData.link_comprovante || '';
const contact = input.contact || {};
const identifier = input.identifier || '';

const listBases = input.listBases || [];
const listFornecedores = input.listFornecedores || [];
const listFormasPagamento = input.listFormasPagamento || [];
const listBasesCentroCusto = input.listBasesCentroCusto || [];
const listNumerosReferencia = input.listNumerosReferencia || [];
const listCodigos = input.listCodigos || [];

let nextStep = step;
let data = Object.assign({}, sessionData);
let message = '';
let listType = null;
let listBase = null;
let valid = false;
let error = '';

if (step === 2 && hasImage && linkComprovante) {
  data.link_comprovante = linkComprovante;
