  if (imageData.valor != null) data.valor = imageData.valor;
  if (imageData.data) data.data_entrada = imageData.data;
  if (imageData.nf) data.nf = imageData.nf;
  nextStep = 3;
  valid = true;
} else if (step === 2 && !hasImage) {
  message = 'Por favor, envie o comprovante (print ou foto da nota).';
  valid = false;
} else {
  switch (step) {
    case 1:
      listType = 'bases';
      if (userInput) {
        if (validarBase(userInput, listBases) || listBases.length === 0) {
          data.base = userInput.trim();
          data.base_centro_custo = data.base;
          nextStep = 2;
          valid = true;
        } else {
          error = 'Base inv�lida. Escolha uma da lista.';
        }
      }
      if (!message && !valid) {
        message = error || 'Para qual base vai registrar esta despesa?\n\nDigite o nome da base.';
        if (listBases.length) message += '\n\n' + formatList(listBases, 'Base');
      }
      break;
    case 2:
      if (!valid) message = 'Por favor, envie o comprovante (print ou foto da nota).';
      break;
    case 3:
      if (userInput) {
        const parsed = parseDataBR(userInput) || (userInput.match(/^\d{4}-\d{2}-\d{2}$/) ? userInput : null);
        if (parsed) {
          data.data_entrada = parsed;
          nextStep = 4;
          valid = true;
        } else {
          error = 'Data inv�lida. Use o formato DD/MM/AAAA.';
        }
      }
      if (!message && !valid) message = error || 'Qual a data da compra? (formato: DD/MM/AAAA)';
      break;
    case 4:
      listType = 'fornecedores';
      if (userInput) {
        data.fornecedor = userInput.trim();
        nextStep = 5;
        valid = true;
      }
      if (!message && !valid) {
        message = 'Qual o fornecedor?';
        if (listFornecedores.length) message += '\n\n' + formatList(listFornecedores, 'Fornecedor');
        message += '\n\nOu digite o nome livremente.';
      }
      break;
    case 5:
      if (userInput && userInput.length >= 3) {
        data.descritivo = userInput.trim().slice(0, 100);
        nextStep = 6;
        valid = true;
      } else if (userInput) error = 'Descreva em 3 a 10 palavras.';
      if (!message && !valid) message = error || 'Descreva em poucas palavras sobre o que foi a compra (ex: Almo�o iFood):';
      break;
    case 6:
      if (userInput) {
        const valor = parseValorBR(userInput) ?? (typeof imageData.valor === 'number' ? imageData.valor : null);
        if (valor !== null && valor > 0) {
          data.valor = valor;
          nextStep = 7;
          valid = true;
        } else {
          error = 'Valor inv�lido. Envie no formato 129,90.';
        }
      }
      if (!message && !valid) message = error || 'Qual o valor? (ex: 129,90)';
      break;
    case 7:
      data.nf = userInput && userInput.toLowerCase() !== 'n�o tenho' ? userInput.trim() : '';
      nextStep = 8;
      valid = true;
      listType = 'formas_pagamento';
      message = 'Qual a forma de pagamento?';
      break;
    case 8:
      listType = 'formas_pagamento';
      if (userInput) {
        if (validarLista(userInput, listFormasPagamento, 'Forma') || listFormasPagamento.length === 0) {
          data.forma_pagamento = userInput.trim();
          nextStep = data.forma_pagamento.toLowerCase().includes('boleto') ? 9 : 10;
          valid = true;
        } else {
          error = 'Forma de pagamento inv�lida. Escolha uma da lista.';
        }
      }
      if (!message && !valid) {
        message = error || 'Qual a forma de pagamento?';
        if (listFormasPagamento.length) message += '\n\n' + formatList(listFormasPagamento, 'Forma');
      }
      break;
    case 9:
      if (userInput) {
        const parsed = parseDataBR(userInput) || (userInput.match(/^\d{4}-\d{2}-\d{2}$/) ? userInput : null);
        if (parsed) {
          data.data_vencimento_boleto = parsed;
          nextStep = 10;
          valid = true;
        } else {
          error = 'Data inv�lida. Use DD/MM/AAAA.';
        }
      }
      if (!message && !valid) message = error || 'Qual a data de vencimento do boleto? (DD/MM/AAAA)';
      break;
    case 10:
      listType = 'bases_centro_custo';
      if (userInput) {
        if (validarLista(userInput, listBasesCentroCusto, 'Nome') || listBasesCentroCusto.length === 0) {
          const item = listBasesCentroCusto.find(x => (x.Nome || x.nome || '').toLowerCase() === userInput.toLowerCase());
          data.base_centro_custo = item && item.base_centro_custo ? item.base_centro_custo : (item && item.Nome ? item.Nome : userInput.trim());
          nextStep = 11;
          valid = true;
        } else {
          error = 'Centro de custo inv�lido. Escolha um da lista.';
        }
      }
      if (!message && !valid) {
        message = error || 'Qual o centro de custo?';
        if (listBasesCentroCusto.length) message += '\n\n' + formatList(listBasesCentroCusto, 'Nome');
      }
      break;
    case 11:
      listType = 'numeros_referencia';
      listBase = data.base;
      if (userInput && userInput.toLowerCase() !== 'pular' && userInput.toLowerCase() !== 'n�o') {
        const item = listNumerosReferencia.find(x => (x.numero_referencia || x['N� refer�ncia'] || '').toLowerCase() === userInput.toLowerCase());
        data.numero_referencia = item ? (item.numero_referencia + ' - ' + (item.descricao || '')).trim() : userInput.trim();
      } else {
        data.numero_referencia = '';
      }
      nextStep = 12;
      valid = true;
      listType = 'codigos';
      listBase = data.base;
      message = 'Escolha o c�digo (ou digite manualmente):';
      break;
    case 12:
      listType = 'codigos';
      listBase = data.base;
      if (userInput) {
        const match = listCodigos.find(x =>
          (x.C�digo || x.numero_referencia || '').toLowerCase() === userInput.toLowerCase() ||
          (x.codigo_completo || '').toLowerCase().includes(userInput.toLowerCase())
        );
        data.codigo = match ? (match.C�digo || match.numero_referencia || userInput.trim()) : userInput.trim();
        nextStep = 13;
        valid = true;
      }
      if (!message && !valid) {
        message = 'Escolha o c�digo (ou digite manualmente):';
        if (listCodigos.length) message += '\n\n' + formatList(listCodigos, 'codigo_completo');
      }
      break;
    case 13:
      if (userInput.toLowerCase() === 'sim' || userInput.toLowerCase() === 's') {
        nextStep = 14;
        valid = true;
        message = 'Registrando...';
      } else if (userInput.toLowerCase() === 'n�o' || userInput.toLowerCase() === 'n') {
        nextStep = 1;
        valid = true;
        message = 'Para editar, reinicie informando a base.';
      } else {
        error = 'Responda sim ou n�o.';
      }
      if (!message && !valid) {
        const resumo = [
          'Base: ' + data.base,
          'Data: ' + data.data_entrada,
          'Fornecedor: ' + data.fornecedor,
          'Descritivo: ' + data.descritivo,
          'Valor: R$ ' + (data.valor || 0).toFixed(2).replace('.', ','),
          'NF: ' + (data.nf || '-'),
          'Forma: ' + data.forma_pagamento,
          data.data_vencimento_boleto ? 'Venc. Boleto: ' + data.data_vencimento_boleto : '',
          'Centro custo: ' + data.base_centro_custo,
          'C�digo: ' + data.codigo
        ].filter(Boolean).join('\n');
        message = error || ('Vou registrar assim:\n\n' + resumo + '\n\nConfirmar? (sim/n�o)');
      }
      break;
    case 14:
      valid = true;
      break;
    default:
      nextStep = 1;
      listType = 'bases';
      message = 'Para qual base vai registrar esta despesa?';
      break;
  }
}

const out = {
  nextStep: nextStep,
  sessionData: data,
  message: message,
  listType: listType,
  listBase: listBase || data.base,
  valid: valid,
  error: error,
  appendLancamento: nextStep === 14 && valid,
  identifier: identifier
};
return [{ json: out }];

const proc = $('Process Step').first().json;
const fetch = $input.first().json;
const data = fetch.data || [];
const tipo = fetch.tipo || proc.listType;
function fmt(items, f) { return (items||[]).map((x,i)=>`${i+1}) ${x[f]||x.nome||x.Base||x.Forma||x.Nome||''}`).join('\n'); }
const field = tipo==='bases'?'Base':tipo==='fornecedores'?'Fornecedor':tipo==='formas_pagamento'?'Forma':tipo==='bases_centro_custo'?'Nome':tipo==='codigos'?'codigo_completo':'numero_referencia';
const listStr = data.length ? '\n\n' + fmt(data, field) : '';
return [{ json: { ...proc, message: (proc.message||'') + listStr } }];
